const inp = $input.first().json;
const body = inp.body || inp;
const errores = [];
const limpiarTel = (v) => v ? String(v).replace(/[^0-9]/g, '') : '';
const cap = (v) => { if (!v) return ''; v = String(v).trim().toLowerCase(); return v.charAt(0).toUpperCase() + v.slice(1); };
let contacto = limpiarTel(body.contacto || body.telefono || body.phone || body.from);
if (!contacto) { contacto = 'desconocido'; errores.push('contacto_ausente'); }
const nombre = body.nombre ? cap(body.nombre) : '';
let canal = String(body.canal || body.channel || 'webhook-test').trim().toLowerCase();
if (!['whatsapp','instagram','web','webhook-test','otro','desconocido'].includes(canal)) canal = 'otro';
let mensaje = String(body.mensaje || body.message || body.texto || '').trim();
if (!mensaje) { errores.push('mensaje_vacio'); }
const timestamp = new Date().toISOString();
return [{ json: { lead: { contacto, nombre, canal, mensaje }, timestamp, errores } }];

// Junta lead + lead existente + stock filtrado + info negocio + historial y arma el prompt minimo para la IA
const base = $('1. Normalizar').first().json;
const lead = base.lead;

const norm = (s) => String(s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
const msg = norm(lead.mensaje);
const findKey = (obj, frag) => Object.keys(obj).find(k => norm(k).includes(frag));

// Lead existente (Buscar Lead emite un item vacio si no hubo match)
let leadExistente = null;
try {
  const rows = $('Buscar Lead').all().map(i => i.json).filter(r => r && r.CONTACTO);
  if (rows.length > 0) leadExistente = rows[0];
} catch (e) {}

// Stock: matchea si algun token (>=3 letras) del MODELO o la MARCA aparece en el mensaje (max 5)
let stockRows = [];
try { stockRows = $('Leer Stock').all().map(i => i.json).filter(r => r && Object.keys(r).length > 0); } catch (e) {}
const tokensDe = (s) => norm(s).split(/[^a-z0-9]+/).filter(t => t.length >= 3);
const msgTokens = new Set(tokensDe(lead.mensaje));
const stockCoincidente = [];
for (const row of stockRows) {
  const kModelo = findKey(row, 'modelo');
  const kMarca = findKey(row, 'marca');
  const toks = tokensDe(kModelo ? row[kModelo] : '').concat(tokensDe(kMarca ? row[kMarca] : ''));
  if (toks.some(t => msgTokens.has(t))) stockCoincidente.push(row);
  if (stockCoincidente.length >= 5) break;
}

// Consulta general de stock/usados (sin modelo puntual): listado compacto de todo el stock
const consultaGeneralStock = /\b(usados?|stock|autos?|vehiculos?|camionetas?|suv|disponibles?|lista|listado|catalogo|modelos)\b|que (tenes|tienen|hay)/.test(msg);
let listadoStock = [];
if (consultaGeneralStock) {
  listadoStock = stockRows.slice(0, 20).map(r => {
    const g = (frag) => { const k = findKey(r, frag); return k ? String(r[k] || '').trim() : ''; };
    return [g('tipo'), g('marca'), g('modelo'), g('ano'), g('color'), g('estado'), g('observ')].filter(Boolean).join(' · ');
  }).filter(Boolean);
}

// Info del negocio (pestana ESCALO_NEGOCIO, pares CLAVE/VALOR). Solo claves con valor real.
let negocioRows = [];
try { negocioRows = $('Leer Negocio').all().map(i => i.json).filter(r => r && Object.keys(r).length > 0); } catch (e) {}
const infoNegocio = [];
for (const row of negocioRows) {
  const kC = findKey(row, 'clave');
  const kV = findKey(row, 'valor');
  if (!kC || !kV) continue;
  const c = String(row[kC] || '').trim();
  const v = String(row[kV] || '').trim();
  if (!c || !v || norm(v) === 'completar') continue;
  infoNegocio.push(c + ': ' + v);
}

// Historial reciente de ESTE contacto (ultimos 6 intercambios previos)
let histRows = [];
try { histRows = $('Leer Historial').all().map(i => i.json).filter(r => r && Object.keys(r).length > 0); } catch (e) {}
const soloDigitos = (s) => String(s || '').replace(/[^0-9]/g, '');
const telCliente = soloDigitos(lead.contacto);
const histCliente = [];
for (const row of histRows) {
  const kTel = findKey(row, 'telefono');
  if (!kTel || !telCliente || soloDigitos(row[kTel]) !== telCliente) continue;
  const kMsg = findKey(row, 'mensaje');
  const kResp = findKey(row, 'respuesta');
  const kTs = findKey(row, 'timestamp');
  histCliente.push({
    ts: kTs ? String(row[kTs] || '') : '',
    cliente: kMsg ? String(row[kMsg] || '') : '',
    ia: kResp ? String(row[kResp] || '') : ''
  });
}
const histReciente = histCliente.slice(-6);
const histTexto = histReciente.map(hx => 'Cliente: ' + hx.cliente + '\nVos respondiste: ' + hx.ia).join('\n');

// Senales deterministas de escalado (independientes de la IA)
const senales = [];
if (/descuent|rebaj|negoci|mejor precio/.test(msg)) senales.push('descuento_negociacion');
if (/financi|cuota|credito|prestamo/.test(msg)) senales.push('financiacion');
if (/entrego|entregar|permuta|mi usado|toma de|tomarian/.test(msg)) senales.push('entrega_usado');
if (/reclam|queja|problema|falla|garant/.test(msg)) senales.push('reclamo');
if (/comprar|reserv|sena|senia|cerrar/.test(msg)) senales.push('cierre_compra');

const lineas = [];
lineas.push('Sos el asistente IA de una concesionaria de autos. Analiza el mensaje del cliente y devolve SOLO un objeto JSON valido. Sin markdown, sin texto extra, sin bloques de codigo.');
lineas.push('');
lineas.push('REGLAS ESTRICTAS:');
lineas.push('- NUNCA inventes precios, stock, colores, financiacion, descuentos ni disponibilidad. Solo pode usar lo que figura en STOCK CONFIRMADO.');
lineas.push('- Si el dato que pide el cliente no esta en STOCK CONFIRMADO: no lo afirmes y marca requiere_escalado=true.');
lineas.push('- Horario, direccion, telefono, medios de pago, promociones y datos del negocio: respondelos SOLO con lo que figura en INFO DEL NEGOCIO. Si el dato no figura ahi, no lo inventes: respondele con una frase natural pidiendo confirmar ese dato (sin mencionar "asesor" ni el proceso interno) y marca requiere_escalado=true.');
lineas.push('- MEDIOS DE PAGO: si el cliente pregunta en general como puede pagar o que medios de pago hay, NO listes las opciones aunque figuren en INFO DEL NEGOCIO. Respondele natural que hay varias formas de manejarlo y preguntale como estaba pensando manejarse (contado, financiado, o entregando un usado en parte de pago). Recien si pregunta por UN medio puntual (ej: aceptan tarjeta?) confirmale SOLO ese dato segun INFO DEL NEGOCIO y segui con una pregunta que avance la venta. Tenes PROHIBIDO mencionar medios de pago que el cliente no pregunto (nada de: tambien podes pagar con..., o explorar financiacion, etc.).');
lineas.push('- Respondé UNICAMENTE lo que el cliente pregunto en su mensaje. No agregues datos que no pidio aunque figuren en INFO DEL NEGOCIO o en el stock (ejemplo: si pregunta la ubicacion, no menciones el horario salvo que tambien lo haya preguntado).');
lineas.push('- CONSULTA GENERAL DE USADOS/AUTOS/STOCK (el cliente pregunta que hay, sin nombrar un modelo): NO pases el listado de entrada. Respondele natural que hay variedad y calificalo organico con UNA pregunta por mensaje: que busca (auto, SUV o camioneta), presupuesto aproximado, 0km o usado. SOLO si el cliente insiste (segun HISTORIAL RECIENTE ya lo calificaste o ya esquivaste la lista una vez y la vuelve a pedir, o pide explicito que le pases todo lo que hay) pasale el LISTADO GENERAL DE STOCK: una linea por unidad con año, modelo, kilometraje (solo si figura) y color. Incluye tambien las unidades en ingreso si figuran asi en su estado.');
lineas.push('- Si STOCK CONFIRMADO dice sin coincidencias y el modelo tampoco esta en LISTADO GENERAL DE STOCK: tenes PROHIBIDO afirmar que hay una unidad o describirla (nada de año, km ni color inventados). Decile que ahora no lo tenes disponible y ofrece averiguarlo, manteniendo coherencia con lo que ya le dijiste antes segun HISTORIAL RECIENTE.');
lineas.push('- Para 0KM: solo confirma un color si figura en la columna COLORES DISP. del stock.');
lineas.push('- Para USADO con condicion EN TALLER: no prometas visita inmediata.');
lineas.push('- Nunca menciones ni estimes el valor de toma de un usado. Eso lo define un humano.');
lineas.push('- dominio_patente y vehiculo_entregado refieren SOLO al vehiculo que el cliente ENTREGA en parte de pago. Nunca copies ahi la patente de un auto del stock. Si el cliente no entrega nada, dejalos vacios.');
lineas.push('- Escalado obligatorio (requiere_escalado=true) si hay: pedido de descuento o negociacion, consulta especifica de financiacion, entrega de usado en parte de pago, reclamo, o intencion de cerrar compra/reserva/sena.');
lineas.push('- FINANCIACION: no des detalles de planes ni tasas. Decile que hay opciones de financiacion y pedile el DNI y con cuanto anticipo cuenta, para que el equipo le prepare una simulacion. Marca requiere_escalado=true.');
lineas.push('- ENTREGA_USADO: decile que tomamos usados en parte de pago, sujeto a peritaje. Pedile marca, modelo, año, kilometraje y estado general del vehiculo para avanzar con una tasacion aproximada que hace el equipo. Nunca des vos un valor. Marca requiere_escalado=true.');
lineas.push('- Si el cliente pasa su DNI, anticipo o datos de su usado, incluilos en resumen_vendedor.');
lineas.push('- Si falta informacion confirmada o tenes poca certeza: requiere_escalado=true y confianza baja.');
lineas.push('');
lineas.push('CONVERSACION (ida y vuelta):');
lineas.push('- Tu objetivo es avanzar al cliente paso a paso hasta que agende una visita o quede calificado para el vendedor.');
lineas.push('- Usa HISTORIAL RECIENTE como memoria: no repitas saludos, presentaciones ni preguntas ya hechas. Si HISTORIAL RECIENTE no esta vacio, tenes PROHIBIDO saludar de nuevo (nada de "Hola" ni usar el nombre como apertura): segui la charla directo, como si ya estuviera en curso.');
lineas.push('- Si el cliente responde algo que ya veniamos hablando (color, modelo, visita), interpretalo en ese contexto.');
lineas.push('- Cerra tu respuesta_cliente con UNA sola pregunta concreta que haga avanzar la venta (que modelo busca, 0km o usado, medio de pago, o proponer dia/hora de visita), salvo que corresponda escalar o el cliente ya haya agendado.');
lineas.push('- Tono: humano y natural, porteño moderado (vos, dale, mirá) sin exagerar ni caer en caricatura. Mensajes cortos estilo WhatsApp, como los escribiria un vendedor real.');
lineas.push('- No sones a asistente virtual: nada de "estoy aqui para ayudarte", "en que mas te puedo ayudar?" ni respuestas enlatadas. Varia la forma de arrancar cada mensaje.');
lineas.push('- Prioriza preguntar antes que informar: da el minimo de informacion necesaria y termina calificando al cliente. Ejemplo: si preguntan por medios de pago, no listes todo; responde que hay varias opciones y pregunta con que medio estaba pensando manejarse.');
lineas.push('');
lineas.push('INTENCION (elegir UNA): DISPONIBILIDAD, PRECIO, STOCK, PROMOCION, FICHA_TECNICA, FINANCIACION, ENTREGA_USADO, AGENDAR_VISITA, DESCUENTO_NEGOCIACION, RECLAMO, INFO_GENERAL, TRABAJO_CV, POSVENTA_SERVICE, NO_ENTENDIDO');
lineas.push('INFO_GENERAL = pregunta por horario, direccion, ubicacion, telefono, medios de pago u otra info del negocio.');
lineas.push('TRABAJO_CV = pregunta por trabajo, empleo, busqueda laboral o quiere dejar su CV/curriculum.');
lineas.push('POSVENTA_SERVICE = pregunta por service, garantia, taller o post-venta de un vehiculo ya comprado (no es venta de un vehiculo).');
lineas.push('estado_lead: FRIO (consulta generica) | TIBIO (pregunta stock/precio/color/financiacion de un modelo puntual) | CALIENTE (quiere comprar, visitar, reservar o cerrar ya)');
lineas.push('');
lineas.push('resumen_vendedor: breve y accionable, maximo 15 palabras, sin fecha. NO repitas el nombre ni el telefono del cliente (ya figuran en su ficha). Si el cliente cambio de vehiculo de interes o de temperatura, indicalo ahi.');
lineas.push('DEVOLVE EXACTAMENTE ESTA ESTRUCTURA JSON:');
lineas.push('{"intencion":"","confianza":"alta|media|baja","producto_mencionado":"","tipo":"0KM|USADO|","color_preferido":"","medio_pago":"","vehiculo_entregado":"","dominio_patente":"","presupuesto_aprox":"","estado_lead":"FRIO|TIBIO|CALIENTE","requiere_escalado":false,"motivo_escalado":"","quiere_agendar":false,"fecha_hora_visita":"","respuesta_cliente":"","resumen_vendedor":"","accion_recomendada":"","proximo_paso":""}');
lineas.push('');
lineas.push('DATOS:');
lineas.push('INFO DEL NEGOCIO (unica fuente valida para datos del negocio): ' + (infoNegocio.length ? infoNegocio.join(' | ') : 'sin datos cargados'));
lineas.push('HISTORIAL RECIENTE CON ESTE CLIENTE (de mas viejo a mas nuevo):');
lineas.push(histTexto || 'sin historial previo (primer contacto)');
lineas.push('MENSAJE NUEVO DEL CLIENTE: ' + lead.mensaje);
lineas.push('NOMBRE: ' + (lead.nombre || 'desconocido'));
lineas.push('CANAL: ' + lead.canal);
lineas.push('LEAD EXISTENTE: ' + (leadExistente ? JSON.stringify(leadExistente) : 'ninguno (cliente nuevo)'));
lineas.push('STOCK CONFIRMADO (unico stock que existe): ' + (stockCoincidente.length ? JSON.stringify(stockCoincidente) : 'sin coincidencias en stock'));
lineas.push('LISTADO GENERAL DE STOCK (usar SOLO segun la regla de consulta general): ' + (listadoStock.length ? listadoStock.join(' || ') : 'no aplica'));
lineas.push('SENALES DETECTADAS POR SISTEMA: ' + (senales.length ? senales.join(', ') : 'ninguna'));

return [{ json: {
  prompt: lineas.join('\n'),
  lead,
  timestamp: base.timestamp,
  errores: base.errores || [],
  existe: !!leadExistente,
  lead_existente: leadExistente,
  stock_coincidente: stockCoincidente,
  info_negocio: infoNegocio,
  historial_reciente: histReciente,
  senales
} }];

// Parseo y validacion determinista de la salida de la IA
const ctx = $('Preparar Contexto').first().json;
const lead = ctx.lead;

const raw = $input.first().json.text !== undefined ? $input.first().json.text : ($input.first().json.output || '');
let ia = null;
try {
  const limpio = String(raw).replace(/```json|```/g, '').trim();
  const ini = limpio.indexOf('{');
  const fin = limpio.lastIndexOf('}');
  if (ini >= 0 && fin > ini) ia = JSON.parse(limpio.substring(ini, fin + 1));
} catch (e) { ia = null; }

const fallo_parseo = !ia;
if (!ia) ia = { intencion: 'NO_ENTENDIDO', confianza: 'baja', respuesta_cliente: '', resumen_vendedor: 'La IA no devolvio JSON valido. Revisar manualmente.', requiere_escalado: true, motivo_escalado: 'salida_ia_invalida' };

// Enums validados por codigo
const INTS = ['DISPONIBILIDAD','PRECIO','STOCK','PROMOCION','FICHA_TECNICA','FINANCIACION','ENTREGA_USADO','AGENDAR_VISITA','DESCUENTO_NEGOCIACION','RECLAMO','NO_ENTENDIDO','INFO_GENERAL','TRABAJO_CV','POSVENTA_SERVICE'];
if (!INTS.includes(ia.intencion)) ia.intencion = 'NO_ENTENDIDO';
const nrm = (s) => String(s || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const est = nrm(ia.estado_lead);
ia.estado_lead = est === 'CALIENTE' ? 'CALIENTE' : (est === 'TIBIO' ? 'TIBIO' : 'FR\u00cdO');
if (!['alta','media','baja'].includes(ia.confianza)) ia.confianza = 'baja';

// El escalado deterministico manda sobre la IA
const INT_ESC = ['DESCUENTO_NEGOCIACION','FINANCIACION','ENTREGA_USADO','RECLAMO','NO_ENTENDIDO'];
const motivos = [];
if (ia.requiere_escalado === true) motivos.push(ia.motivo_escalado || 'criterio_ia');
if ((ctx.senales || []).length > 0) motivos.push('senales: ' + ctx.senales.join(','));
if (INT_ESC.includes(ia.intencion)) motivos.push('intencion_' + ia.intencion.toLowerCase());
if (ia.confianza === 'baja') motivos.push('confianza_baja');
ia.requiere_escalado = motivos.length > 0;
ia.motivo_escalado = motivos.join(' | ');

// TRABAJO_CV y POSVENTA_SERVICE: respuesta fija, nunca escalan, no las redacta la IA
if (ia.intencion === 'TRABAJO_CV' || ia.intencion === 'POSVENTA_SERVICE') {
  ia.requiere_escalado = false;
  ia.motivo_escalado = '';
  if (ia.intencion === 'TRABAJO_CV') {
    const horarioLinea = (ctx.info_negocio || []).find(l => l.toUpperCase().startsWith('HORARIO'));
    const horarioTxt = horarioLinea ? horarioLinea.split(':').slice(1).join(':').trim() : 'nuestro horario de atencion';
    ia.respuesta_cliente = 'Para dejar tu CV podes acercarte en persona a cualquiera de nuestras sucursales, dentro del horario de atencion: ' + horarioTxt + '.';
  } else {
    ia.respuesta_cliente = 'Estas hablando con el equipo de ventas. Para consultas de post-venta o service, escribinos por WhatsApp al 1151321582.';
  }
}

if (!ia.respuesta_cliente) {
  ia.respuesta_cliente = ia.requiere_escalado
    ? 'Dejame confirmar bien ese dato y te escribo enseguida.'
    : 'Contame un poco mas asi te oriento mejor.';
}

// Fila ESCALO_LEADS: nunca pisar datos existentes con vacio. PRECIO DE TOMA no se toca.
const ex = ctx.lead_existente || {};
const elegir = (nuevo, viejo) => (nuevo !== undefined && nuevo !== null && String(nuevo).trim() !== '') ? String(nuevo).trim() : (viejo !== undefined && viejo !== null ? String(viejo) : '');
const ahora = new Date();
const fecha = ahora.toISOString().substring(0, 10);
// OBSERVACIONES IA: sin fecha, breve. Registra cambios de interes y de temperatura para el vendedor.
let obs = ex['OBSERVACIONES IA'] ? String(ex['OBSERVACIONES IA']) : '';
const cambios = [];
const vehAnt = String(ex['VEHÍCULO DE INTERÉS'] || '').trim();
const vehNuevo = String(ia.producto_mencionado || '').trim();
if (vehNuevo && vehAnt && nrm(vehNuevo) !== nrm(vehAnt)) cambios.push('nuevo interes: ' + vehNuevo + ' (antes ' + vehAnt + ')');
const estAnt = String(ex['ESTADO'] || '').trim();
if (estAnt && nrm(estAnt) !== nrm(ia.estado_lead)) cambios.push('paso de ' + estAnt + ' a ' + ia.estado_lead);
let nota = String(ia.resumen_vendedor || ia.intencion).trim();
// Sin nombre del cliente (ya esta en su columna) y sin notas duplicadas
const nomCli = nrm(lead.nombre || '').trim();
if (nomCli && nrm(nota).startsWith(nomCli)) nota = nota.slice(String(lead.nombre).length).replace(/^[\s,:.\-]+/, '');
if (nota && obs && nrm(obs).includes(nrm(nota))) nota = '';
if (ex['OBSERVACIONES IA'] && nota.length > 90) nota = nota.slice(0, 90);
const partes = cambios.concat(nota ? [nota] : []);
obs = obs ? (obs + ' | ' + partes.join(' | ')) : partes.join(' | ');
if (obs.length > 400) obs = obs.slice(-400);

const fila_lead = {};
fila_lead['FECHA'] = ex['FECHA'] ? String(ex['FECHA']) : fecha;
fila_lead['NOMBRE'] = elegir(lead.nombre, ex['NOMBRE']);
fila_lead['CONTACTO'] = lead.contacto;
fila_lead['ESTADO'] = ia.estado_lead;
fila_lead['VEH\u00cdCULO DE INTER\u00c9S'] = elegir(ia.producto_mencionado, ex['VEH\u00cdCULO DE INTER\u00c9S']);
fila_lead['TIPO'] = elegir(ia.tipo, ex['TIPO']);
fila_lead['COLOR PREFERIDO'] = elegir(ia.color_preferido, ex['COLOR PREFERIDO']);
fila_lead['MEDIO DE PAGO'] = elegir(ia.medio_pago, ex['MEDIO DE PAGO']);
fila_lead['VEH\u00cdCULO ENTREGADO'] = elegir(ia.vehiculo_entregado, ex['VEH\u00cdCULO ENTREGADO']);
fila_lead['DOMINIO/PATENTE'] = elegir(ia.dominio_patente, ex['DOMINIO/PATENTE']);
fila_lead['PRESUPUESTO APROX.'] = elegir(ia.presupuesto_aprox, ex['PRESUPUESTO APROX.']);
fila_lead['OBSERVACIONES IA'] = obs;

// Fila ESCALO_HISTORIAL
const t0 = new Date(ctx.timestamp).getTime();
const fila_historial = {};
fila_historial['TIMESTAMP'] = ctx.timestamp;
fila_historial['TELEFONO'] = lead.contacto;
fila_historial['NOMBRE'] = fila_lead['NOMBRE'];
fila_historial['CANAL'] = lead.canal;
fila_historial['MENSAJE ORIGINAL'] = lead.mensaje;
fila_historial['PRODUCTO MENCIONADO'] = ia.producto_mencionado || '';
fila_historial['INTENCION'] = ia.intencion;
fila_historial['CONFIANZA'] = ia.confianza;
fila_historial['REQUIERE ESCALADO'] = ia.requiere_escalado ? 'SI' : 'NO';
fila_historial['MOTIVO ESCALADO'] = ia.motivo_escalado;
fila_historial['RESPUESTA ENVIADA'] = ia.respuesta_cliente;
fila_historial['TIPO RESPUESTA'] = ia.requiere_escalado ? 'ESCALADO' : 'AUTOMATICA';
fila_historial['ACCION RECOMENDADA'] = ia.accion_recomendada || '';
fila_historial['PROXIMO PASO'] = ia.proximo_paso || (ia.requiere_escalado ? 'derivar_vendedor' : 'responder_automatico');
fila_historial['VENDEDOR ASIGNADO'] = '';
fila_historial['ESTADO EJECUCION'] = fallo_parseo ? 'ERROR_PARSEO_IA' : 'OK';
fila_historial['TIEMPO RESP (SEG)'] = Math.max(0, Math.round((Date.now() - t0) / 1000));
fila_historial['NOTAS LOG'] = (ctx.errores && ctx.errores.length) ? ctx.errores.join(',') : '';

const ORDEN = ['TIMESTAMP','TELEFONO','NOMBRE','CANAL','MENSAJE ORIGINAL','PRODUCTO MENCIONADO','INTENCION','CONFIANZA','REQUIERE ESCALADO','MOTIVO ESCALADO','RESPUESTA ENVIADA','TIPO RESPUESTA','ACCION RECOMENDADA','PROXIMO PASO','VENDEDOR ASIGNADO','ESTADO EJECUCION','TIEMPO RESP (SEG)','NOTAS LOG'];
const fila_historial_valores = ORDEN.map(k => fila_historial[k] === undefined || fila_historial[k] === null ? '' : fila_historial[k]);
return [{ json: { ia, fila_lead, fila_historial, fila_historial_valores, lead, existe: ctx.existe, timestamp: ctx.timestamp } }];

const v = $('Validar Salida IA').first().json;
const ia = v.ia;
return [{ json: {
  ok: true,
  workflow: 'ESCALO-MVP-V2',
  lead: { contacto: v.lead.contacto, nombre: v.fila_lead['NOMBRE'] || '', nuevo: !v.existe },
  analisis: {
    intencion: ia.intencion,
    confianza: ia.confianza,
    estado_lead: ia.estado_lead,
    requiere_escalado: ia.requiere_escalado,
